#include <stdio.h>

int main() {
    // For Loop: Print 1 to 3
    printf("For Loop: ");
    for(int i = 1; i <= 3; i++) {
        printf("%d ", i);
    }

    // While Loop: Print 1 to 3
    printf("\nWhile Loop: ");
    int j = 1;
    while(j <= 3) {
        printf("%d ", j);
        j++;
    }

    // Do-While: Runs at least once
    printf("\nDo-While: ");
    int k = 10;
    do {
        printf("%d ", k);
    } while(k < 5); // False, but prints 10

    return 0;
}

