#include <stdio.h>

int fibonacci(int n) {
    if (n <= 1) return n; // Base case
    return fibonacci(n - 1) + fibonacci(n - 2); // Recursive case
}

int main() {
    int limit = 6;
    printf("Fibonacci at position %d is %d", limit, fibonacci(limit));
    return 0;
}

