#include <stdio.h>

int main() {
    int arr[3] = {100, 200, 300};
    int *p = arr; // Points to arr[0]

    printf("Index 0: %d at address %p\n", *p, p);

    p++; // Moves to next integer (usually 4 bytes ahead)
    printf("Index 1: %d at address %p\n", *p, p);

    p = p + 1;
    printf("Index 2: %d at address %p\n", *p, p);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, *ptr, i;

    printf("Enter number of elements: ");
    scanf("%d", &n);

    // Allocating memory using malloc
    ptr = (int*) malloc(n * sizeof(int));

    if (ptr == NULL) {
        printf("Memory not allocated. System Full!\n");
        exit(0);
    }

    printf("Memory successfully allocated using malloc.\n");

    // Input elements
    for (i = 0; i < n; ++i) {
        ptr[i] = i + 1;
    }

    // Display elements
    printf("The elements are: ");
    for (i = 0; i < n; ++i) {
        printf("%d ", ptr[i]);
    }

    // Free the memory
    free(ptr);
    printf("\nMemory successfully freed.\n");

    return 0;
}

