#include <string.h>

// Defining the structure
struct Student {
    int rollNo;
    char name[50];
    float marks;
};

int main() {
    // Declaring a structure variable
    struct Student s1;

    // Assigning values
    s1.rollNo = 101;
    strcpy(s1.name, "Rahul");
    s1.marks = 88.5;

    // Printing values
    printf("Student Details:\n");
    printf("Roll No: %d\n", s1.rollNo);
    printf("Name: %s\n", s1.name);
    printf("Marks: %.2f\n", s1.marks);

    return 0;
}

