#include <stdio.h>

int main() {
    FILE *fp;
    fp = fopen("test.txt", "w"); // Open for writing

    if (fp == NULL) {
        printf("Error opening file!");
        return 1;
    }

    fprintf(fp, "Hello! This is stored in a file.\n");
    fprintf(fp, "File handling is powerful.");

    fclose(fp); // Always close the file
    printf("Data successfully written.");

    return 0;
}

#include <stdio.h>

int main() {
    FILE *fp;
    char buffer[100];
    fp = fopen("test.txt", "r"); // Open for reading

    if (fp == NULL) {
        printf("File not found!");
        return 1;
    }

    // Read file line by line until EOF (End Of File)
    while (fgets(buffer, 100, fp) != NULL) {
        printf("%s", buffer);
    }

    fclose(fp);
    return 0;
}

